msg.payload = [
    {
        status: (Number(msg.payload.values["PLC_MITSU_FX3U:green_light"]) === 1) ? 0 : 1
    },
    {
        factory: 'Bông Bạch Tuyết Vĩnh Lộc',
        system: 'Công đoạn thành phẩm',
